using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using NumSharp;
using NumSharp.Backends.Iteration;

namespace NumSharp.UnitTest.Backends.Iterators
{
    /// <summary>
    /// Battle tests verifying NumSharp NpyIter produces EXACT same results as NumPy nditer.
    /// Each test includes the expected NumPy output in comments for verification.
    ///
    /// These tests were generated by running actual NumPy code and comparing results.
    /// </summary>
    [TestClass]
    public class NpyIterNumPyBattleTests
    {
        // =====================================================================
        // Test 1: Basic C-order iteration
        // NumPy: [0, 1, 2, 3, 4, 5]
        // =====================================================================
        [TestMethod]
        public void Battle_BasicCOrderIteration()
        {
            // NumPy:
            // arr = np.arange(6).reshape(2, 3)
            // with np.nditer(arr) as it:
            //     for x in it: values.append(int(x))
            // Result: [0, 1, 2, 3, 4, 5]

            var arr = np.arange(6).reshape(2, 3);
            var expected = new[] { 0, 1, 2, 3, 4, 5 };

            using var iter = NpyIterRef.New(arr);
            var values = new List<int>();

            do
            {
                values.Add(iter.GetValue<int>(0));
            } while (iter.Iternext());

            CollectionAssert.AreEqual(expected, values.ToArray(),
                "C-order iteration must match NumPy exactly");
        }

        // =====================================================================
        // Test 2: F-order iteration
        // NumPy: [0, 3, 1, 4, 2, 5]
        // =====================================================================
        [TestMethod]
        public void Battle_FOrderIteration()
        {
            // NumPy:
            // arr = np.arange(6).reshape(2, 3)
            // with np.nditer(arr, order='F') as it:
            //     for x in it: values.append(int(x))
            // Result: [0, 3, 1, 4, 2, 5]

            var arr = np.arange(6).reshape(2, 3);
            var expected = new[] { 0, 3, 1, 4, 2, 5 };

            using var iter = NpyIterRef.New(arr, order: NPY_ORDER.NPY_FORTRANORDER);
            var values = new List<int>();

            do
            {
                values.Add(iter.GetValue<int>(0));
            } while (iter.Iternext());

            CollectionAssert.AreEqual(expected, values.ToArray(),
                "F-order iteration must match NumPy exactly");
        }

        // =====================================================================
        // Test 3: Multi-operand iteration with broadcasting
        // NumPy: [(0, 0), (1, 1), (2, 2), (0, 3), (1, 4), (2, 5)]
        // =====================================================================
        [TestMethod]
        public void Battle_MultiOperandBroadcasting()
        {
            // NumPy:
            // a = np.arange(3)
            // b = np.arange(6).reshape(2, 3)
            // with np.nditer([a, b]) as it:
            //     for x, y in it: pairs.append((int(x), int(y)))
            // Result: [(0, 0), (1, 1), (2, 2), (0, 3), (1, 4), (2, 5)]

            var a = np.arange(3);
            var b = np.arange(6).reshape(2, 3);
            var expected = new[] { (0, 0), (1, 1), (2, 2), (0, 3), (1, 4), (2, 5) };

            using var iter = NpyIterRef.MultiNew(
                2, new[] { a, b },
                NpyIterGlobalFlags.None,
                NPY_ORDER.NPY_KEEPORDER,
                NPY_CASTING.NPY_NO_CASTING,
                new[] { NpyIterPerOpFlags.READONLY, NpyIterPerOpFlags.READONLY });

            var pairs = new List<(int, int)>();

            do
            {
                pairs.Add((iter.GetValue<int>(0), iter.GetValue<int>(1)));
            } while (iter.Iternext());

            CollectionAssert.AreEqual(expected, pairs.ToArray(),
                "Multi-operand broadcasting must match NumPy exactly");
        }

