        // =====================================================================
        // Test 5: Transposed array iteration
        // NumPy iterates in memory order, so transposed (F-contiguous) iterates [0,1,2,3,4,5]
        // =====================================================================
        [TestMethod]
        public void Battle_TransposedArrayIteration()
        {
            // NumPy:
            // arr = np.arange(6).reshape(2, 3)
            // trans = arr.T
            // with np.nditer(trans) as it:
            //     for x in it: values.append(int(x))
            // Result: [0, 1, 2, 3, 4, 5] (memory order, not logical order)

            var arr = np.arange(6).reshape(2, 3);
            var trans = arr.T;
            var expected = new[] { 0, 1, 2, 3, 4, 5 };

            using var iter = NpyIterRef.New(trans);
            var values = new List<int>();

            do
            {
                values.Add(iter.GetValue<int>(0));
            } while (iter.Iternext());

            CollectionAssert.AreEqual(expected, values.ToArray(),
                "Transposed array iteration must match NumPy memory order");
        }

        // =====================================================================
        // Test 6: Reversed array iteration
        // NumPy flips negative strides to iterate memory order: [0,1,2,3,4,5]
        // =====================================================================
        [TestMethod]
        public void Battle_ReversedArrayIteration()
        {
            // NumPy:
            // arr = np.arange(6).reshape(2, 3)
            // rev = arr[::-1, ::-1]
            // with np.nditer(rev) as it:
            //     for x in it: values.append(int(x))
            // Result: [0, 1, 2, 3, 4, 5] (memory order due to NEGPERM)

            var arr = np.arange(6).reshape(2, 3);
            var rev = arr["::-1, ::-1"];
            var expected = new[] { 0, 1, 2, 3, 4, 5 };

            using var iter = NpyIterRef.New(rev);
            var values = new List<int>();

            do
            {
                values.Add(iter.GetValue<int>(0));
            } while (iter.Iternext());

            CollectionAssert.AreEqual(expected, values.ToArray(),
                "Reversed array iteration must match NumPy memory order (NEGPERM)");
        }

        // =====================================================================
        // Test 7: Multi-index tracking
        // NumPy: [((0,0),0), ((0,1),1), ((0,2),2), ((1,0),3), ((1,1),4), ((1,2),5)]
        // =====================================================================
        [TestMethod]
        public void Battle_MultiIndexTracking()
        {
            // NumPy:
            // with np.nditer(arr, flags=['multi_index']) as it:
            //     while not it.finished:
            //         indices.append((it.multi_index, int(it[0])))
            //         it.iternext()

            var arr = np.arange(6).reshape(2, 3);
            var expected = new[]
            {
                ((0L, 0L), 0), ((0L, 1L), 1), ((0L, 2L), 2),
                ((1L, 0L), 3), ((1L, 1L), 4), ((1L, 2L), 5)
            };

            using var iter = NpyIterRef.New(arr, NpyIterGlobalFlags.MULTI_INDEX);
            var results = new List<((long, long), int)>();
            Span<long> mi = stackalloc long[2];

            do
            {
                iter.GetMultiIndex(mi);
                results.Add(((mi[0], mi[1]), iter.GetValue<int>(0)));
            } while (iter.Iternext());

            CollectionAssert.AreEqual(expected, results.ToArray(),
                "Multi-index tracking must match NumPy exactly");
        }

