        // =====================================================================
        // Test 12: Empty array
        // NumPy: Iteration count = 0
        // =====================================================================
        [TestMethod]
        public void Battle_EmptyArrayIteration()
        {
            // NumPy:
            // empty = np.array([], dtype=np.int32)
            // with np.nditer(empty, flags=['zerosize_ok']) as it:
            //     for x in it: count += 1
            // Result: count = 0

            var empty = np.array(new int[0]);

            using var iter = NpyIterRef.New(empty, NpyIterGlobalFlags.ZEROSIZE_OK);

            int count = 0;
            // For empty arrays, Iternext returns false immediately or the loop doesn't execute
            if (iter.IterSize > 0)
            {
                do
                {
                    count++;
                } while (iter.Iternext());
            }

            Assert.AreEqual(0, count, "Empty array iteration count must be 0");
        }

        // =====================================================================
        // Test 13: Complex broadcasting (1,4) x (3,1) = (3,4)
        // NumPy pairs in row-major: (0,0),(1,0),(2,0),(3,0), (0,1),(1,1)...
        // =====================================================================
        [TestMethod]
        public void Battle_ComplexBroadcasting()
        {
            // NumPy:
            // a = np.arange(4).reshape(1, 4)  # [[0,1,2,3]]
            // b = np.arange(3).reshape(3, 1)  # [[0],[1],[2]]
            // pairs: [(0,0),(1,0),(2,0),(3,0), (0,1),(1,1),(2,1),(3,1), (0,2),(1,2),(2,2),(3,2)]

            var a = np.arange(4).reshape(1, 4);
            var b = np.arange(3).reshape(3, 1);

            // NumPy iterates in C-order over broadcast shape (3,4)
            var expected = new[]
            {
                (0, 0), (1, 0), (2, 0), (3, 0),
                (0, 1), (1, 1), (2, 1), (3, 1),
                (0, 2), (1, 2), (2, 2), (3, 2)
            };

            using var iter = NpyIterRef.MultiNew(
                2, new[] { a, b },
                NpyIterGlobalFlags.None,
                NPY_ORDER.NPY_KEEPORDER,
                NPY_CASTING.NPY_NO_CASTING,
                new[] { NpyIterPerOpFlags.READONLY, NpyIterPerOpFlags.READONLY });

            var pairs = new List<(int, int)>();

            do
            {
                pairs.Add((iter.GetValue<int>(0), iter.GetValue<int>(1)));
            } while (iter.Iternext());

            CollectionAssert.AreEqual(expected, pairs.ToArray(),
                "Complex broadcasting must match NumPy exactly");
        }

