        // Test 15: 50 operands (beyond NumPy 1.x limit of 32)
        // NumPy 2.x: First values = [0, 1, 2, ..., 49]
        // =====================================================================
        [TestMethod]
        public void Battle_50Operands()
        {
            // NumPy:
            // arrays50 = [np.array([i]) for i in range(50)]
            // First values: [0, 1, 2, ..., 49]

            var arrays = new NDArray[50];
