        // =====================================================================
        // Test 16: 100 operands (NumSharp unlimited, beyond NumPy's NPY_MAXARGS=64)
        // =====================================================================
        [TestMethod]
        public void Battle_100Operands_BeyondNumPyLimit()
        {
            // NumSharp supports unlimited operands
            // This tests beyond NumPy's NPY_MAXARGS=64 limit

            var arrays = new NDArray[100];
            var opFlags = new NpyIterPerOpFlags[100];
            var expectedFirst = new int[100];

            for (int i = 0; i < 100; i++)
            {
                arrays[i] = np.array(new int[] { i * 10, i * 10 + 1 });
                opFlags[i] = NpyIterPerOpFlags.READONLY;
                expectedFirst[i] = i * 10;  // First element
            }

            using var iter = NpyIterRef.MultiNew(100, arrays, NpyIterGlobalFlags.None,
                NPY_ORDER.NPY_KEEPORDER, NPY_CASTING.NPY_NO_CASTING, opFlags);

            Assert.AreEqual(100, iter.NOp, "Should have 100 operands");
            Assert.AreEqual(2, iter.IterSize, "Should iterate 2 times (array length)");

            // Verify first iteration values
            var firstValues = new int[100];
            for (int op = 0; op < 100; op++)
            {
                firstValues[op] = iter.GetValue<int>(op);
            }
            CollectionAssert.AreEqual(expectedFirst, firstValues,
                "100 operand first values must be correct");

            // Move to second iteration and verify
            Assert.IsTrue(iter.Iternext(), "Should have second iteration");
            var secondValues = new int[100];
            var expectedSecond = new int[100];
            for (int op = 0; op < 100; op++)
            {
                secondValues[op] = iter.GetValue<int>(op);
                expectedSecond[op] = op * 10 + 1;  // Second element
            }
            CollectionAssert.AreEqual(expectedSecond, secondValues,
                "100 operand second values must be correct");

            // Should be finished
            Assert.IsFalse(iter.Iternext(), "Should be finished after 2 iterations");
        }

        // =====================================================================
        // Test 17: Verify iteration order with non-contiguous view
        // =====================================================================
        [TestMethod]
        public void Battle_NonContiguousViewOrder()
        {
            // Create a non-contiguous view via slicing
            var arr = np.arange(20).reshape(4, 5);
            var view = arr["::2, 1::2"];  // Every other row, columns 1,3

            // Expected shape is (2, 2) with values [[1,3], [11,13]]
            // C-order iteration: [1, 3, 11, 13]
            var expected = new[] { 1, 3, 11, 13 };

            using var iter = NpyIterRef.New(view);
            var values = new List<int>();

            do
            {
                values.Add(iter.GetValue<int>(0));
            } while (iter.Iternext());

            CollectionAssert.AreEqual(expected, values.ToArray(),
                "Non-contiguous view must iterate in correct order");
        }

        // =====================================================================
        // Test 18: Verify multi-index with transposed array
        // =====================================================================
        [TestMethod]
        public void Battle_MultiIndexWithTransposed()
        {
            var arr = np.arange(6).reshape(2, 3);
            var trans = arr.T;  // Shape (3, 2)

            // Multi-index should follow the logical shape (3, 2)
            // But iteration follows memory order

            using var iter = NpyIterRef.New(trans, NpyIterGlobalFlags.MULTI_INDEX);

            var results = new List<(long row, long col, int val)>();
            Span<long> mi = stackalloc long[2];
            do
            {
                iter.GetMultiIndex(mi);
                results.Add((mi[0], mi[1], iter.GetValue<int>(0)));
            } while (iter.Iternext());

            // Verify we get all 6 elements with valid multi-indices
            Assert.AreEqual(6, results.Count);

            // Values should be 0-5 (memory order)
            var values = results.Select(r => r.val).ToArray();
            CollectionAssert.AreEqual(new[] { 0, 1, 2, 3, 4, 5 }, values);
        }

        // =====================================================================
        // Test 19: Verify GotoMultiIndex works correctly
        // =====================================================================
        [TestMethod]
        public void Battle_GotoMultiIndex()
        {
            var arr = np.arange(12).reshape(3, 4);

            using var iter = NpyIterRef.New(arr, NpyIterGlobalFlags.MULTI_INDEX);

            // Jump to position (1, 2) which should have value 6
            iter.GotoMultiIndex(new long[] { 1, 2 });
            Assert.AreEqual(6, iter.GetValue<int>(0));

            // Jump to position (2, 3) which should have value 11
            iter.GotoMultiIndex(new long[] { 2, 3 });
            Assert.AreEqual(11, iter.GetValue<int>(0));

            // Jump back to start
            iter.GotoMultiIndex(new long[] { 0, 0 });
            Assert.AreEqual(0, iter.GetValue<int>(0));
        }

        // =====================================================================
        // Test 20: Verify external loop flag
        // =====================================================================
        [TestMethod]
        public void Battle_ExternalLoop()
        {
            // NumPy with external_loop returns contiguous chunks
            var arr = np.arange(12).reshape(3, 4);

            using var iter = NpyIterRef.New(arr, NpyIterGlobalFlags.EXTERNAL_LOOP);

            // With external loop on contiguous array, should get one large chunk
            Assert.IsTrue(iter.HasExternalLoop);

            // Inner loop size should be the full array for contiguous
            long* innerSizePtr = iter.GetInnerLoopSizePtr();
            // For contiguous C-order array, inner loop should cover all elements
            Assert.IsTrue(*innerSizePtr >= 1, "Inner loop size should be at least 1");
        }

        // =====================================================================
        // Test 21: Verify buffered iteration with type casting
        // =====================================================================
        [TestMethod]
        public void Battle_BufferedWithCasting()
        {
            // Create int32 array, iterate as float64
            var arr = np.array(new int[] { 1, 2, 3 });

            using var iter = NpyIterRef.AdvancedNew(
                1, new[] { arr },
                NpyIterGlobalFlags.BUFFERED,
                NPY_ORDER.NPY_KEEPORDER,
                NPY_CASTING.NPY_SAFE_CASTING,
                new[] { NpyIterPerOpFlags.READONLY },
                new[] { NPTypeCode.Double });

            var values = new List<double>();
            do
            {
                values.Add(iter.GetValue<double>(0));
            } while (iter.Iternext());

            CollectionAssert.AreEqual(new[] { 1.0, 2.0, 3.0 }, values.ToArray(),
                "Buffered casting must convert int32 to float64 correctly");
        }

        // =====================================================================
        // Test 22: Full iteration then reset
        // =====================================================================
        [TestMethod]
        public void Battle_FullIterationThenReset()
        {
            var arr = np.arange(6).reshape(2, 3);

            using var iter = NpyIterRef.New(arr);

            // First full iteration
            var values1 = new List<int>();
            do
            {
                values1.Add(iter.GetValue<int>(0));
            } while (iter.Iternext());

            // Reset
            iter.Reset();

            // Second full iteration should produce same results
            var values2 = new List<int>();
            do
            {
                values2.Add(iter.GetValue<int>(0));
            } while (iter.Iternext());

            CollectionAssert.AreEqual(values1, values2,
                "Reset must allow identical re-iteration");
        }

        // =====================================================================
        // Test 23: Copy iterator preserves state
        // =====================================================================
        [TestMethod]
        public void Battle_CopyIteratorPreservesState()
        {
            var arr = np.arange(10);

            using var iter = NpyIterRef.New(arr);

            // Advance to position 5
            for (int i = 0; i < 5; i++)
                iter.Iternext();

            Assert.AreEqual(5, iter.GetValue<int>(0));

            // Copy
            using var copy = iter.Copy();

            // Copy should be at same position
            Assert.AreEqual(5, copy.GetValue<int>(0));

            // Advancing copy shouldn't affect original
            copy.Iternext();
            Assert.AreEqual(6, copy.GetValue<int>(0));
            Assert.AreEqual(5, iter.GetValue<int>(0));
        }

        // =====================================================================
        // Test 24: Ranged iteration
        // =====================================================================
        [TestMethod]
        public void Battle_RangedIteration()
        {
            var arr = np.arange(10);

            using var iter = NpyIterRef.New(arr);

            // Set range to iterate only elements 3-7
            iter.ResetToIterIndexRange(3, 7);

            var values = new List<int>();
            do
            {
                values.Add(iter.GetValue<int>(0));
            } while (iter.Iternext());

            CollectionAssert.AreEqual(new[] { 3, 4, 5, 6 }, values.ToArray(),
                "Ranged iteration must only iterate specified range");
        }
    }
}
